struct Resource { 
    id: u32,
}

impl Drop for Resource {
    fn drop(&mut self) {
        println!("Dropping Resource with ID: {}", self.id);
    }
}

struct Guard {
    resource: Option<Resource>,
}

impl Guard {
    fn new(id: u32) -> Self {
        Self { 
            resource: Some(Resource { id }),
        }
    }
}

impl Drop for Guard {
    fn drop(&mut self) {
        if let Some(resource) = self.resource.take() {
            drop(resource);
        }
    }
}

fn main() {
    println!("Entering scope...");
    let _guard = Guard::new(42);
    println!("Leaving scope.");
}
